function initStickyHeader(){const e=document.getElementById("siteHeader"),d=document.getElementById("sitePreheader"),s=document.getElementById("headerWrapper"),n=document.getElementById("headerPlaceholder");if(!e||!d||!s||!n)return;const i=window.matchMedia("(min-width: 980px)"),t=()=>{const o=i.matches?d.offsetHeight:0,r=s.offsetHeight;n.style.height=`${r}px`,window.scrollY>o?e.classList.add("is-scrolled"):e.classList.remove("is-scrolled")};t(),window.addEventListener("scroll",t,{passive:!0}),window.addEventListener("resize",t)}window.addEventListener("DOMContentLoaded",initStickyHeader);
